module top_module(inverted_out, in0, in1, select);parameter bits = 32;	
output [bits-1:0] inverted_out;
input [bits-1:0] in0, in1;
input select;

	reg [bits-1:0] inverted_out;

	always @ (select or in0 or in1)
	case (select)	
		0: inverted_out = in0;
		1: inverted_out = in1;

		default: inverted_out = 65'bx ;

	endcase
endmodule
